desktop_page = <Page url='https://gautamsachdeva.com/profile/'>

    def test_photo_galleries_load_images(desktop_page: Page):
        """ALL gallery pages contain visible, loaded gallery images.

        Gallery images use WOW.js (visibility:hidden until scroll-triggered).
        If WOW.js fails to init, images stay hidden — this test catches that.
        """
        gallery_pages = {
            "/photo-gallery/": "Mentors",
            "/photos-with-mystics-teachers-authors/": "Mystics, Teachers, Authors",
            "/photos-from-talks/": "Photos from Talks",
            "/profile/": "Profile",
        }

        failures = []
        for path, name in gallery_pages.items():
            resp = desktop_page.goto(f"{BASE_URL}{path}", wait_until="domcontentloaded")
            if not resp or resp.status >= 400:
                failures.append(f"{name} ({path}): HTTP {resp.status if resp else 'no response'}")
                continue

            # Wait for images and WOW.js animation init
            desktop_page.wait_for_load_state("networkidle")
            # Scroll to trigger WOW.js visibility on all images
            desktop_page.evaluate("window.scrollTo(0, document.body.scrollHeight)")
            desktop_page.wait_for_timeout(1500)

            # All gallery pages use the Flavor theme media gallery widget
            gallery_items = desktop_page.locator(".m-media-gallery__item")
            count = gallery_items.count()
            if count < 3:
                failures.append(
                    f"{name} ({path}): only {count} gallery items (expected >= 3)"
                )
                continue

            # Force WOW.js hidden images to be visible so the browser actually
            # downloads them (headless Chrome may skip hidden images).
            # Then re-trigger any lazy-loaded src attributes and wait for loads.
            stats = desktop_page.evaluate("""() => {
                const items = document.querySelectorAll('.m-media-gallery__item');
                // Force visibility on all gallery items and their children
                for (const item of items) {
                    item.style.visibility = 'visible';
                    item.style.opacity = '1';
                    for (const el of item.querySelectorAll('*')) {
                        el.style.visibility = 'visible';
                        el.style.opacity = '1';
                    }
                }
                // Re-trigger lazy-loaded images by re-assigning src
                const imgs = [];
                for (const item of items) {
                    const img = item.querySelector('img');
                    if (img) {
                        const src = img.getAttribute('src') || img.dataset.src || '';
                        if (src && !src.startsWith('data:')) {
                            img.src = src;
                        }
                        imgs.push(img);
                    }
                }
                return { total: items.length, imgCount: imgs.length };
            }""")

            # Give images time to download after forcing visibility
            desktop_page.wait_for_timeout(3000)

            # Now check which images actually loaded
            result = desktop_page.evaluate("""() => {
                const items = document.querySelectorAll('.m-media-gallery__item');
                let loaded = 0;
                const broken = [];
                for (const item of items) {
                    const img = item.querySelector('img');
                    if (img && img.naturalWidth > 0) {
                        loaded++;
                    } else if (img) {
                        broken.push(img.getAttribute('src') || '(no src)');
                    }
                }
                return { total: items.length, loaded, broken: broken.slice(0, 3) };
            }""")
            # 80% threshold — headless Chrome + WOW.js can miss some images
            # but 0% or very low means real breakage (CDN down, broken src)
            if result["loaded"] < result["total"] * 0.8:
                failures.append(
                    f"{name} ({path}): {result['loaded']}/{result['total']} images loaded "
                    f"(sample broken: {result['broken']})"
                )

